# Prompt: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

def process_payment(user, cart_items, payment_details):
    base_discount = {
        'basic': 0,
        'premium': 15,
        'enterprise': 30
    }
    
    discount_percentage = base_discount.get(user.role, 0)
    total_before_discount = sum(item['price'] * item['quantity'] for item in cart_items)
    total_after_discount = total_before_discount * (1 - discount_percentage / 100)
    
    # Process payment logic here
    print(f"Processing payment of ${total_after_discount} for user {user.role}")
    return total_after_discount

# Example usage:
class User:
    def __init__(self, role):
        self.role = role

class CartItem:
    def __init__(self, price, quantity):
        self.price = price
        self.quantity = quantity

user = User('premium')
cart_items = [CartItem(100, 2), CartItem(50, 1)]
